import React, { useState } from "react";

const ASSET_API = "http://localhost:5001";

export default function AssetForm({ tenantId, asset, onSuccess }) {
  const [name, setName] = useState(asset?.name || "");
  const [type, setType] = useState(asset?.type || "VM");
  const [loading, setLoading] = useState(false);

  const handleSubmit = async (e) => {
    e.preventDefault();

    if (!tenantId) {
      alert("Please select a tenant first");
      return;
    }

    if (!name.trim()) {
      alert("Asset name is required");
      return;
    }

    try {
      setLoading(true);

      const isEdit = !!asset;
      const url = isEdit
        ? `${ASSET_API}/assets/${asset.id}?tenantId=${encodeURIComponent(tenantId)}`
        : `${ASSET_API}/assets`;

      const method = isEdit ? "PUT" : "POST";

      const payload = {
        tenantId,
        name,
        type,
      };

      const res = await fetch(url, {
        method,
        headers: {
          "Content-Type": "application/json",
        },
        body: JSON.stringify(payload),
      });

      if (!res.ok) {
        throw new Error("Failed to save asset");
      }

      if (onSuccess) {
        onSuccess();
      }
    } catch (err) {
      console.error(err);
      alert("Failed to save asset");
    } finally {
      setLoading(false);
    }
  };

  return (
    <form className="form-shell" onSubmit={handleSubmit}>
      <h2 className="form-title">{asset ? "Edit Asset" : "Create Asset"}</h2>
      <p className="form-subtitle">Add or update an infrastructure asset.</p>

      <div className="form-group">
        <label className="form-label">Asset Name</label>
        <input
          className="form-input"
          type="text"
          placeholder="Enter asset name"
          value={name}
          onChange={(e) => setName(e.target.value)}
        />
      </div>

      <div className="form-group">
        <label className="form-label">Asset Type</label>
        <select
          className="form-input"
          value={type}
          onChange={(e) => setType(e.target.value)}
        >
          <option value="VM">VM</option>
          <option value="DB">DB</option>
          <option value="SWITCH">SWITCH</option>
        </select>
      </div>

      <button className="btn btn-primary form-submit" type="submit" disabled={loading}>
        {loading ? "Saving..." : asset ? "Update Asset" : "Create Asset"}
      </button>
    </form>
  );
}
